// HasFunnels applies the HasEdge predicate on the "funnels" edge.
func HasFunnels() predicate.Site {
	return predicate.Site(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, FunnelsTable, FunnelsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasFunnelsWith applies the HasEdge predicate on the "funnels" edge with a given conditions (other predicates).
func HasFunnelsWith(preds ...predicate.Funnel) predicate.Site {
	return predicate.Site(func(s *sql.Selector) {
		step := newFunnelsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

